package com.google.gson.internal.bind;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.reflect.TypeToken;

import org.junit.jupiter.api.Test;

class TypeAdaptersTest {

  @Test
  void newFactory_create_returnsAdapterForUnboxedType() {
    TypeAdapter<Number> adapter = mock(TypeAdapter.class);
    TypeAdapterFactory factory = TypeAdapters.newFactory(int.class, Integer.class, adapter);

    Gson gson = mock(Gson.class);
    TypeToken<Integer> typeToken = TypeToken.get(int.class);

    @SuppressWarnings("unchecked")
    TypeAdapter<Integer> created = (TypeAdapter<Integer>) factory.create(gson, typeToken);

    assertSame(adapter, created);
  }

  @Test
  void newFactory_create_returnsAdapterForBoxedType() {
    TypeAdapter<Number> adapter = mock(TypeAdapter.class);
    TypeAdapterFactory factory = TypeAdapters.newFactory(int.class, Integer.class, adapter);

    Gson gson = mock(Gson.class);
    TypeToken<Integer> typeToken = TypeToken.get(Integer.class);

    @SuppressWarnings("unchecked")
    TypeAdapter<Integer> created = (TypeAdapter<Integer>) factory.create(gson, typeToken);

    assertSame(adapter, created);
  }

  @Test
  void newFactory_create_returnsNullForOtherType() {
    TypeAdapter<Number> adapter = mock(TypeAdapter.class);
    TypeAdapterFactory factory = TypeAdapters.newFactory(int.class, Integer.class, adapter);

    Gson gson = mock(Gson.class);
    TypeToken<Long> typeToken = TypeToken.get(Long.class);

    TypeAdapter<Long> created = factory.create(gson, typeToken);

    assertNull(created);
  }

  @Test
  void newFactory_toString_containsBoxedAndUnboxedTypeNamesAndAdapter() {
    TypeAdapter<Number> adapter = mock(TypeAdapter.class);
    TypeAdapterFactory factory = TypeAdapters.newFactory(int.class, Integer.class, adapter);

    String toString = factory.toString();

    assertTrue(toString.contains(Integer.class.getName()));
    assertTrue(toString.contains(int.class.getName()));
    assertTrue(toString.contains(adapter.toString()));
  }
}
